-- Generated by scripts/export-editorial-guides-sql.mjs
-- Canonical seed for R Guide editorial lists.

create table if not exists public.editorial_guides (
  id text primary key,
  slug text not null unique,
  category text not null,
  country text not null,
  city text,
  neighborhood text,
  list jsonb not null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

alter table public.editorial_guides enable row level security;

create or replace function public.set_updated_at()
returns trigger
language plpgsql
as $$
begin
  new.updated_at = now();
  return new;
end;
$$;

drop trigger if exists editorial_guides_set_updated_at on public.editorial_guides;

create trigger editorial_guides_set_updated_at
before update on public.editorial_guides
for each row
execute function public.set_updated_at();

drop policy if exists "Editorial guides are readable" on public.editorial_guides;

create policy "Editorial guides are readable"
on public.editorial_guides
for select
using (true);

create index if not exists editorial_guides_category_idx on public.editorial_guides (category);
create index if not exists editorial_guides_country_city_idx on public.editorial_guides (country, city);
create index if not exists editorial_guides_neighborhood_idx on public.editorial_guides (neighborhood);
create index if not exists editorial_guides_list_gin_idx on public.editorial_guides using gin (list);

insert into public.editorial_guides (
  id,
  slug,
  category,
  country,
  city,
  neighborhood,
  list
)
values
  ('list-barcelona-top-parks', 'barcelona-top-parks-in-the-city', 'Nature', 'Spain', 'Barcelona', null, '{"id":"list-barcelona-top-parks","slug":"barcelona-top-parks-in-the-city","title":"Top Parks in the City","description":"A Barcelona green-space route built around landmark parks, historic gardens, and major hilltop viewpoints, with a mix of architecture, culture, and city panoramas.","url":"https://www.google.com/maps/search/top+parks+in+barcelona","category":"Nature","location":{"city":"Barcelona","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-nature","name":"R Nature","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-17T00:00:00.000Z","stops":[{"id":"park-guell","name":"Parc Guell","coordinates":[41.4145,2.1527],"description":"Gaudi''s landmark hilltop park combines sculptural architecture, mosaic terraces, and elevated city views; part of the UNESCO-listed Works of Antoni Gaudi.","hours":{"default":"Daily ~9:30 AM-7:30 PM."}},{"id":"parc-de-la-ciutadella","name":"Parc de la Ciutadella","coordinates":[41.3888,2.186],"description":"Barcelona''s central 19th-century park, created after the old citadel and shaped for the 1888 Universal Exhibition, with the Cascada Monumental, lake boating, and broad lawns.","hours":{"default":"Daily ~10:00 AM-10:30 PM."}},{"id":"montjuic-park","name":"Montjuic Park","coordinates":[41.363,2.1679],"description":"A large hill park linking gardens, lookouts, and major cultural landmarks, from Montjuic Castle and MNAC to Olympic-era venues and botanical spaces.","hours":{"default":"Park 24h; gardens/sites ~10:00 AM-sunset."}},{"id":"parc-del-laberint-dhorta","name":"Parc del Laberint d''Horta","coordinates":[41.4397,2.1477],"description":"Barcelona''s oldest garden (late 18th century), known for its cypress maze, neoclassical design, romantic landscaping, and quieter setting near Collserola.","hours":{"winter":"10:00 AM-6:00 PM","spring":"10:00 AM-7:00 PM","summer":"10:00 AM-8:00 PM","fall":"10:00 AM-7:00 PM"}},{"id":"parc-de-cervantes","name":"Parc de Cervantes","coordinates":[41.3871,2.1123],"description":"Pedralbes park centered on one of Barcelona''s strongest rose collections, with more than 10,000 bushes and peak blooms from late spring into summer.","hours":{"default":"Daily 8:00 AM-sunset."}},{"id":"parc-del-guinardo-bunkers-del-carmel","name":"Parc del Guinardo / Bunkers del Carmel","coordinates":[41.4183,2.1527],"description":"Hilltop park-and-viewpoint area around Turó de la Rovira (Bunkers del Carmel), known for former anti-aircraft battery remains and wide 360-degree skyline views.","hours":{"default":"Park 24h; Bunkers ~8:30 AM-7:30 PM (night-restricted)."}}],"sources":[{"name":"Turisme de Barcelona - Parks & Gardens","url":"https://www.barcelonaturisme.com/wv3/en/page/32/parks-and-gardens.html"},{"name":"Ajuntament de Barcelona - Parks directory","url":"https://ajuntament.barcelona.cat/ecologiaurbana/en/services/the-city-works/parks-and-gardens"},{"name":"Lonely Planet - Best parks in Barcelona","url":"https://www.lonelyplanet.com/articles/best-parks-barcelona"},{"name":"Time Out - Best parks and gardens in Barcelona","url":"https://www.timeout.com/barcelona/things-to-do/best-parks-in-barcelona"},{"name":"Conde Nast Traveler - Barcelona destination","url":"https://www.cntraveler.com/destinations/barcelona"},{"name":"Park Guell official","url":"https://parkguell.barcelona/en"},{"name":"UNESCO - Works of Antoni Gaudi","url":"https://whc.unesco.org/en/list/320"},{"name":"Parc de la Ciutadella page","url":"https://www.barcelonaturisme.com/wv3/en/page/117/parc-de-la-ciutadella.html"},{"name":"Montjuic page","url":"https://www.barcelonaturisme.com/wv3/en/page/120/montjuic.html"},{"name":"Parc del Laberint d''Horta page","url":"https://www.barcelonaturisme.com/wv3/en/page/118/parc-del-laberint-dhorta.html"},{"name":"Parc de Cervantes page","url":"https://www.barcelonaturisme.com/wv3/en/page/119/parc-de-cervantes.html"},{"name":"Turo de la Rovira / Bunkers del Carmel page","url":"https://www.barcelonaturisme.com/wv3/en/page/124/turo-de-la-rovira.html"},{"name":"Google Maps","url":"https://maps.google.com"},{"name":"Tripadvisor - Barcelona parks attractions","url":"https://www.tripadvisor.com/Attractions-g187497-Activities-c57-Barcelona_Catalonia.html"}]}'::jsonb),
  ('list-barcelona-gothic-quarter-restaurants', 'barcelona-gothic-quarter-restaurants', 'Food', 'Spain', 'Barcelona', 'Gothic Quarter', '{"id":"list-barcelona-gothic-quarter-restaurants","slug":"barcelona-gothic-quarter-restaurants","title":"Restaurants Worth Booking","description":"Gothic Quarter restaurants that avoid the old-town tourist trap pattern, from historic Catalan dining rooms to tight modern tasting menus.","url":"https://www.google.com/maps/search/gothic+quarter+restaurants+barcelona","category":"Food","location":{"city":"Barcelona","neighborhood":"Gothic Quarter","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-food","name":"R Food","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"gothic-la-sosenga","name":"La Sosenga","coordinates":[41.3826,2.1749],"description":"Small Catalan tasting-menu room that works old recipes into sharper monthly menus; a strong choice when you want serious cooking without Eixample formality.","price":"$$","priceSource":"Time Out","hours":{"mon":"Closed","tue":"1:00 PM-4:00 PM","wed":"1:00 PM-4:00 PM","thu":"1:00 PM-4:00 PM","fri":"1:00 PM-4:00 PM, 8:00 PM-11:00 PM","sat":"1:00 PM-4:00 PM, 8:00 PM-11:00 PM","sun":"Closed"}},{"id":"gothic-bistrot-levante","name":"Bistrot Levante","coordinates":[41.3833,2.1769],"description":"Small glassy bistro on Placeta de Manuel Ribé with Eastern Mediterranean plates, good vegetables, and a calm old-city feel that beats most tourist-menu options nearby.","price":"$$","priceSource":"Eater / Google Maps","hours":{"mon":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","tue":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","wed":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","thu":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","fri":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sat":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sun":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM"}},{"id":"gothic-kak-koy","name":"Kak Koy","coordinates":[41.385,2.1755],"description":"Japanese robata counter using Barcelona market seafood and produce; the bar seats make it feel precise and lively without turning into formal fine dining.","price":"$$$","priceSource":"Eater / Google Maps","hours":{"mon":"Closed","tue":"7:00 PM-10:30 PM","wed":"7:00 PM-10:30 PM","thu":"7:00 PM-10:30 PM","fri":"7:00 PM-10:30 PM","sat":"7:00 PM-10:30 PM","sun":"Closed"}},{"id":"gothic-la-plata-restaurant","name":"Bar La Plata","coordinates":[41.3818,2.1799],"description":"Tiny 1945 tavern with a deliberately short menu; go for fried fish, tomato salad, butifarra, and the pleasure of a place that never needed reinvention.","price":"$","priceSource":"Tripadvisor / Google Maps","hours":{"mon":"Closed","tue":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","wed":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","thu":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","fri":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","sat":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","sun":"Closed"}},{"id":"gothic-capet","name":"Capet","coordinates":[41.3816,2.1764],"description":"Intimate contemporary Catalan restaurant on a narrow Gothic lane, with chef-led tasting menus and enough calm to feel like a proper reservation night.","price":"$$$","priceSource":"MICHELIN Guide / Resy","hours":{"mon":"Closed","tue":"7:00 PM-10:30 PM","wed":"7:00 PM-10:30 PM","thu":"7:00 PM-10:30 PM","fri":"7:00 PM-10:30 PM","sat":"7:00 PM-10:30 PM","sun":"Closed"}},{"id":"gothic-sensi-bistro","name":"Sensi Bistro","coordinates":[41.3803,2.1771],"description":"Creative small-plates bistro that suits groups who want shareable tapas with a little more polish than the surrounding Plaça Reial churn.","price":"$$","priceSource":"Tripadvisor / Google Maps","hours":{"mon":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","tue":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","wed":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","thu":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","fri":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sat":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sun":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM"}}],"sources":[{"name":"Time Out - Best restaurants in Barcelona","url":"https://www.timeout.com/barcelona/restaurants/best-restaurants-in-barcelona"},{"name":"The Infatuation - Best Restaurants in Barcelona","url":"https://www.theinfatuation.com/barcelona/guides/best-restaurants-hotels-barcelona"},{"name":"Eater - Old City restaurants","url":"https://www.eater.com/maps/barcelona-old-city-gothic-quarter-best-restaurants"},{"name":"MICHELIN Guide - Capet","url":"https://guide.michelin.com/us/en/catalunya/barcelona/restaurant/capet"},{"name":"Restaurants for Kings - Gothic Quarter restaurants","url":"https://restaurantsforkings.com/blog/gothic-quarter-barcelona-restaurants-guide-2026.html"},{"name":"Tripadvisor - Gothic Quarter restaurants","url":"https://www.tripadvisor.com/Restaurants-g187497-zfn7237169-Barcelona_Catalonia.html"},{"name":"Google Maps","url":"https://maps.google.com"}]}'::jsonb),
  ('list-barcelona-el-born-restaurants', 'barcelona-el-born-restaurants', 'Food', 'Spain', 'Barcelona', 'El Born', '{"id":"list-barcelona-el-born-restaurants","slug":"barcelona-el-born-restaurants","title":"Restaurants Worth Booking","description":"El Born restaurants with real pull: seafood counters, natural-wine rooms, market-adjacent kitchens, and tapas classics that still justify the crowd.","url":"https://www.google.com/maps/search/el+born+restaurants+barcelona","category":"Food","location":{"city":"Barcelona","neighborhood":"El Born","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-food","name":"R Food","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"born-cal-pep-restaurant","name":"Cal Pep","coordinates":[41.3835,2.1839],"description":"Counter-first Born classic where the move is seafood tapas, rapid service, and letting the room''s momentum decide the order.","price":"$$$","priceSource":"The Infatuation / Google Maps","hours":{"mon":"Closed","tue":"1:00 PM-3:30 PM, 8:00 PM-11:00 PM","wed":"1:00 PM-3:30 PM, 8:00 PM-11:00 PM","thu":"1:00 PM-3:30 PM, 8:00 PM-11:00 PM","fri":"1:00 PM-3:30 PM, 8:00 PM-11:30 PM","sat":"1:00 PM-3:30 PM, 8:00 PM-11:30 PM","sun":"Closed"}},{"id":"born-bar-del-pla-restaurant","name":"Bar del Pla","coordinates":[41.3857,2.1817],"description":"Retro-feeling local haunt with natural wine, modern tapas, and a tight dining room that rewards booking instead of wandering in hungry.","price":"$$","priceSource":"The Infatuation / Google Maps","hours":{"mon":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","tue":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","wed":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","thu":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","fri":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sat":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sun":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM"}},{"id":"born-fismuler","name":"Fismuler","coordinates":[41.3867,2.1846],"description":"Hip Mediterranean restaurant inside Rec Comtal, strong for raw seafood, seasonal plates, and the cheesecake that tends to hijack the table conversation.","price":"$$$","priceSource":"The Infatuation / Google Maps","hours":{"mon":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","tue":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","wed":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","thu":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","fri":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sat":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sun":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM"}},{"id":"born-bar-brutal","name":"Bar Brutal","coordinates":[41.3849,2.1811],"description":"Natural-wine pioneer with lively small plates; better for curious drinkers who want dinner to feel spontaneous without being careless.","price":"$$","priceSource":"The Infatuation / Instagram","hours":{"mon":"7:00 PM-12:00 AM","tue":"7:00 PM-12:00 AM","wed":"7:00 PM-12:00 AM","thu":"7:00 PM-12:00 AM","fri":"1:00 PM-4:00 PM, 7:00 PM-12:30 AM","sat":"1:00 PM-4:00 PM, 7:00 PM-12:30 AM","sun":"1:00 PM-4:00 PM, 7:00 PM-12:00 AM"}},{"id":"born-cuines-santa-caterina","name":"Cuines Santa Caterina","coordinates":[41.3867,2.1788],"description":"Market-side all-day standby under Santa Caterina''s colorful roof, handy when you need reliable rice, noodles, grilled plates, and broad hours.","price":"$$","priceSource":"The Infatuation / Google Maps","hours":{"mon":"12:00 PM-12:00 AM","tue":"12:00 PM-12:00 AM","wed":"12:00 PM-12:00 AM","thu":"12:00 PM-12:00 AM","fri":"12:00 PM-1:00 AM","sat":"12:00 PM-1:00 AM","sun":"12:00 PM-12:00 AM"}},{"id":"born-el-xampanyet-restaurant","name":"El Xampanyet","coordinates":[41.3847,2.1836],"description":"Packed cava-and-tapas institution near the Picasso Museum, still best approached as a quick, salty, high-energy meal rather than a lingering dinner.","price":"$","priceSource":"The Infatuation / Tripadvisor","hours":{"mon":"7:00 PM-11:00 PM","tue":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","wed":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","thu":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","fri":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","sat":"12:00 PM-3:30 PM","sun":"Closed"}}],"sources":[{"name":"The Infatuation - El Born","url":"https://www.theinfatuation.com/barcelona/neighborhoods/el-born"},{"name":"The Infatuation - Best Restaurants in Barcelona","url":"https://www.theinfatuation.com/barcelona/guides/best-restaurants-hotels-barcelona"},{"name":"Eater - Old City restaurants","url":"https://www.eater.com/maps/barcelona-old-city-gothic-quarter-best-restaurants"},{"name":"Time Out - Barcelona restaurants","url":"https://www.timeout.com/barcelona/restaurants"},{"name":"Tripadvisor - Barcelona restaurants","url":"https://www.tripadvisor.com/Restaurants-g187497-Barcelona_Catalonia.html"},{"name":"Google Maps","url":"https://maps.google.com"}]}'::jsonb),
