  ('list-barcelona-el-born-culture', 'barcelona-el-born-culture', 'Culture', 'Spain', 'Barcelona', 'El Born', '{"id":"list-barcelona-el-born-culture","slug":"barcelona-el-born-culture","title":"Culture Anchors","description":"El Born cultural stops connecting Picasso, medieval mercantile Barcelona, music, and the neighborhood''s dense museum-and-church circuit.","url":"https://www.google.com/maps/search/el+born+culture+barcelona","category":"Culture","location":{"city":"Barcelona","neighborhood":"El Born","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-culture","name":"R Culture","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"born-picasso-museum","name":"Museu Picasso","coordinates":[41.3853,2.1815],"description":"Five medieval palaces holding Picasso''s formative Barcelona work, especially strong for early drawings, Blue Period context, and the Las Meninas series.","hours":{"mon":"Closed","tue":"9:00 AM-8:00 PM","wed":"9:00 AM-8:00 PM","thu":"9:00 AM-9:00 PM","fri":"9:00 AM-9:00 PM","sat":"9:00 AM-9:00 PM","sun":"9:00 AM-8:00 PM"}},{"id":"born-santa-maria-del-mar","name":"Basílica de Santa Maria del Mar","coordinates":[41.3839,2.1822],"description":"Austere Catalan Gothic basilica built by the Ribera guilds, with soaring stonework that feels more neighborhood-made than monumental.","hours":{"m