  ('list-gabriel-first-guide', 'gabriel-first-guide', 'Activities', 'United States', 'San Francisco', null, '{"id":"list-gabriel-first-guide","slug":"gabriel-first-guide","title":"SF Visitor Guide","description":"A first-time San Francisco route spanning waterfront landmarks, iconic parks, major museums, and city viewpoints worth planning around.","url":"https://maps.app.goo.gl/ipATDsbmTuXVr8hc9?g_st=ac","category":"Activities","location":{"city":"San Francisco","country":"United States","continent":"North America","scope":"city"},"creator":{"id":"user-gabriel-soyka","name":"Gabriel Soyka","avatar":"https://i.pravatar.cc/160?img=59"},"upvotes":1,"createdAt":"2026-04-21T00:00:00.000Z","submissionType":"guide","stops":[{"id":"gabriel-sf-ferry-building","name":"Ferry Building","coordinates":[37.7954425,-122.3936136],"description":"Historic Embarcadero landmark with standout local food vendors, bayfront promenades, and easy access to ferries and Market Street."},{"id":"gabriel-sf-fishermans-wharf","name":"Fisherman''s Wharf","coordinates":[37.8084354,-122.4157509],"description":"High-energy waterfront district for classic first-time sights, pier walks, and quick routes toward North Beach and the bay."},{"id":"gabriel-sf-palace-of-fine-arts","name":"Palace of Fine Arts","coordinates":[37.8029308,-122.4484231],"description":"Grand Beaux-Arts rotunda and lagoon setting that works best for golden-hour photos and a slower walk before sunset."},{"id":"gabriel-sf-alamo-square","name":"Alamo Square Park","coordinates":[37.7763694,-122.434819],"description":"One of the best skyline lawn views in the city, framed by the Painted Ladies and ideal for a short viewpoint stop."},{"id":"gabriel-sf-de-young","name":"de Young Museum","coordinates":[37.771469,-122.4686755],"description":"Major Golden Gate Park museum with strong permanent collections and a tower lookout that gives broad western-city views."},{"id":"gabriel-sf-legion-of-honor","name":"Legion of Honor","coordinates":[37.7845231,-122.5007596],"description":"Fine arts museum on the ocean edge with a calmer pace, dramatic approaches, and nearby access to Lands End trails."},{"id":"gabriel-sf-lombard","name":"Lombard St","coordinates":[37.8020179,-122.4195579],"description":"Iconic switchback block that is busy most of the day; best paired with a short uphill walk for better full-street views."},{"id":"gabriel-sf-vermont","name":"Vermont St (The real “Crookedest Street in the World.”)","coordinates":[37.7589957,-122.4039109],"description":"Local alternative to Lombard with tighter turns, fewer crowds, and a more neighborhood feel in Potrero Hill."},{"id":"gabriel-sf-bison-paddock","name":"Bison Paddock","coordinates":[37.7696864,-122.4982325],"description":"Unexpected Golden Gate Park stop where a small bison herd adds a quirky wildlife break on a west-side loop."},{"id":"gabriel-sf-amoeba","name":"Amoeba Music","coordinates":[37.7691734,-122.4526639],"description":"Legendary Haight record store with deep vinyl selection and strong local culture energy for an indoor break."},{"id":"gabriel-sf-rodeo-beach","name":"Rodeo Beach Coastal Trailhead","coordinates":[37.8322377,-122.5395782],"description":"Marin Headlands launch point for rugged coastal walks, sweeping Pacific views, and photogenic bridge-backdrop angles."},{"id":"gabriel-sf-duboce","name":"Duboce Park","coordinates":[37.7695967,-122.4333344],"description":"Compact neighborhood green space that works as a relaxed reset between Haight, Mission, and central transit lines."},{"id":"gabriel-sf-grandview","name":"Grandview Park","coordinates":[37.7564222,-122.4717361],"description":"Steep stair climb to a compact summit with wide city-to-ocean panoramas and one of SF’s strongest quick viewpoints."},{"id":"gabriel-sf-dolores","name":"Mission Dolores Park","coordinates":[37.7602015,-122.4267959],"description":"Flagship social park with broad downtown views, strong afternoon atmosphere, and easy walkability into the Mission."}],"sources":[{"name":"Google Maps shared list","url":"https://maps.app.goo.gl/ipATDsbmTuXVr8hc9?g_st=ac"}]}'::jsonb),
  ('list-gabriel-experience-dolores-sunset', 'gabriel-experience-dolores-sunset', 'Activities', 'United States', 'San Francisco', null, '{"id":"list-gabriel-experience-dolores-sunset","slug":"gabriel-experience-dolores-sunset","title":"Dolores Park Golden Hour","description":"Caught sunset on the upper slope with a full downtown skyline glow and a packed local after-work crowd.","url":"https://maps.google.com/?q=Mission+Dolores+Park+San+Francisco","category":"Activities","submissionType":"journal","journal":{"visitedAt":"2026-04-18","note":"Best around 6:30-7:30 PM with a light layer, then walked down Valencia for dinner."},"location":{"city":"San Francisco","country":"United States","continent":"North America","scope":"city"},"creator":{"id":"user-gabriel-soyka","name":"Gabriel Soyka","avatar":"https://i.pravatar.cc/160?img=59"},"upvotes":1,"createdAt":"2026-04-18T00:00:00.000Z","stops":[{"id":"gabriel-exp-dolores-stop","name":"Mission Dolores Park","coordinates":[37.7602015,-122.4267959],"description":"Sunset lawn session with skyline views."}],"sources":[{"name":"Personal experience","url":"https://maps.google.com/?q=Mission+Dolores+Park+San+Francisco"}]}'::jsonb),
  ('list-gabriel-experience-ferry-morning', 'gabriel-experience-ferry-morning', 'Activities', 'United States', 'San Francisco', null, '{"id":"list-gabriel-experience-ferry-morning","slug":"gabriel-experience-ferry-morning","title":"Ferry Building Morning Loop","description":"Started early at the Ferry Building, grabbed coffee, then walked north along the Embarcadero before crowds built.","url":"https://maps.google.com/?q=Ferry+Building+San+Francisco","category":"Activities","submissionType":"journal","journal":{"visitedAt":"2026-04-12","note":"Weekday mornings are easiest; great first stop before crossing into North Beach."},"location":{"city":"San Francisco","country":"United States","continent":"North America","scope":"city"},"creator":{"id":"user-gabriel-soyka","name":"Gabriel Soyka","avatar":"https://i.pravatar.cc/160?img=59"},"upvotes":1,"createdAt":"2026-04-12T00:00:00.000Z","stops":[{"id":"gabriel-exp-ferry-stop","name":"Ferry Building","coordinates":[37.7954425,-122.3936136],"description":"Early walk, food hall, waterfront start."}],"sources":[{"name":"Personal experience","url":"https://maps.google.com/?q=Ferry+Building+San+Francisco"}]}'::jsonb),
  ('list-gabriel-experience-headlands-wind', 'gabriel-experience-headlands-wind', 'Nature', 'United States', 'San Francisco', null, '{"id":"list-gabriel-experience-headlands-wind","slug":"gabriel-experience-headlands-wind","title":"Windy Marin Headlands Run","description":"Quick headlands run from Rodeo Beach trailhead with strong wind, dramatic coastline, and clear bridge-back views.","url":"https://maps.google.com/?q=Rodeo+Beach+Coastal+Trailhead","category":"Nature","submissionType":"journal","journal":{"visitedAt":"2026-03-30","note":"Bring a windbreaker even on sunny days; visibility changes fast."},"location":{"city":"San Francisco","country":"United States","continent":"North America","scope":"city"},"creator":{"id":"user-gabriel-soyka","name":"Gabriel Soyka","avatar":"https://i.pravatar.cc/160?img=59"},"upvotes":1,"createdAt":"2026-03-30T00:00:00.000Z","stops":[{"id":"gabriel-exp-headlands-stop","name":"Rodeo Beach Coastal Trailhead","coordinates":[37.8322377,-122.5395782],"description":"Short run with high-impact ocean views."}],"sources":[{"name":"Personal experience","url":"https://maps.google.com/?q=Rodeo+Beach+Coastal+Trailhead"}]}'::jsonb)
